-- Update webinar_reminder_2h template to include {{zoom_link}} button
UPDATE email_templates 
SET body_html = '<div style="background-color: #ffc105; padding: 20px; text-align: center;"><img src="https://xzlhssqqbajqhnsmbucf.supabase.co/storage/v1/object/public/training-media/1766508615455-8wv0cee7jwr.png" alt="Pure Life Center" style="max-height: 50px; margin-bottom: 10px;" /><h1 style="color: #ffffff; margin: 0; font-size: 24px;">Webinar już za 2 godziny!</h1></div><!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin: 0; padding: 0; font-family: Arial, sans-serif; background-color: #f4f4f4;"><table width="100%" cellpadding="0" cellspacing="0" style="max-width: 600px; margin: 0 auto; background-color: #ffffff;"><tr><td style="padding: 40px 30px;"><h2 style="color: #1a1a1a; margin-bottom: 20px;">{{imię}}, zaczynamy za 2 godziny! 🚀</h2><p style="color: #444; font-size: 16px; line-height: 1.6;">Webinar <strong style="color: #16a34a;">{{event_title}}</strong> rozpocznie się o <strong>{{event_time}}</strong>.</p><p style="text-align: center; margin: 30px 0;"><a href="{{zoom_link}}" style="display: inline-block; background: #16a34a; color: white; padding: 16px 32px; text-decoration: none; border-radius: 6px; font-weight: bold; font-size: 18px;">🚀 DOŁĄCZ DO ZOOM</a></p><p style="color: #666; font-size: 14px; text-align: center;">Link do spotkania: <a href="{{zoom_link}}" style="color: #16a34a;">{{zoom_link}}</a></p><p style="color: #444; font-size: 15px; line-height: 1.8; margin-top: 25px;">📅 Data: <strong>{{event_date}}</strong><br>👤 Prowadzący: <strong>{{host_name}}</strong></p><p style="color: #666; font-size: 14px; margin-top: 20px; padding: 15px; background: #f0fdf4; border-radius: 6px;">📝 Przygotuj się — zarezerwuj czas i przygotuj notatnik!</p></td></tr><tr><td style="background-color: #f8f8f8; padding: 20px 30px; text-align: center;"><p style="color: #999; font-size: 12px; margin: 0;">© 2025 Pure Life Center. Wszystkie prawa zastrzeżone.</p></td></tr></table></body></html>',
    updated_at = now()
WHERE internal_name = 'webinar_reminder_2h' AND is_active = true;